export default {
  name: "IctAssets",
  components: {
    Icon
  },
  data() {
    return {
      CATEGORIES,
      STATUSES,
      CONDITIONS,
      items: [],
      loading: false,
      error: "",
      searchQuery: "",
      searchDebounce: null,
      filterCategory: "",
      filterStatus: "",
      filterCondition: "",
      showModal: false,
      editing: null,
      form: emptyForm(),
      submitting: false,
      submitError: "",
      photoPreview: "",
      photoBase64: "",
      photoFileName: "",
      photoCleared: false,
      photoError: "",
      activeTab: "identity",
      tabs: [{
        key: "identity",
        label: "Identity",
        icon: "mdi:identifier"
      }, {
        key: "technical",
        label: "Technical",
        icon: "mdi:chip"
      }, {
        key: "assignment",
        label: "Assignment",
        icon: "mdi:account-arrow-right-outline"
      }, {
        key: "acquisition",
        label: "Acquisition",
        icon: "mdi:cart-outline"
      }]
    };
  },
  computed: {
    stats() {
      const inUse = this.items.filter(x => x.status === "in-use" || x.status === "deployed").length;
      const repair = this.items.filter(x => x.status === "for-repair").length;
      const storage = this.items.filter(x => x.status === "in-storage").length;
      const expiringWarranty = this.items.filter(x => {
        if (!x.warrantyExpiry) return false;
        const t = new Date(x.warrantyExpiry).getTime();
        const now = Date.now();
        const in60 = now + 60 * 24 * 60 * 60 * 1000;
        return t >= now && t <= in60;
      }).length;
      return [{
        label: "Total Assets",
        value: this.items.length,
        icon: "mdi:devices"
      }, {
        label: "Active / Deployed",
        value: inUse,
        icon: "mdi:check-decagram-outline"
      }, {
        label: "In Storage",
        value: storage,
        icon: "mdi:archive-outline"
      }, {
        label: "For Repair",
        value: repair,
        icon: "mdi:wrench-outline"
      }, {
        label: "Warranty <60d",
        value: expiringWarranty,
        icon: "mdi:shield-alert-outline"
      }];
    },
    warrantyState() {
      if (!this.form.warrantyExpiry) return null;
      const t = new Date(this.form.warrantyExpiry).getTime();
      if (Number.isNaN(t)) return null;
      const now = Date.now();
      if (t < now) return {
        label: "Warranty expired",
        color: "text-red-400"
      };
